        try {
            p.parse(aspectRatio);
        } catch (ParseException pEx ) {
            throw new BridgeException
                (ctx, e, pEx, ERR_ATTRIBUTE_VALUE_MALFORMED,
                 new Object[] {SVG_PRESERVE_ASPECT_RATIO_ATTRIBUTE,
                                   aspectRatio, pEx });
        }

        return getPreserveAspectRatioTransform(vb, ph.align, ph.meet, w, h);
    }

